// [L1] Pass to Layer 2 — BINARY ANCHOR POINT
// ============================================================
// Node ini adalah titik simpan binary terakhir yang bisa
// selalu direferensikan oleh node manapun sesudahnya dengan:
//   $('[L1] Pass to Layer 1').first().binary
//
// Ini diperlukan karena Gemini node (dan Redis node) tidak
// meneruskan binary di outputnya.
// ============================================================

const item = $input.first();

// Ambil binary dari Compute node (sumber asli)
const computeNode  = $('[L1] Compute 3 Image Hashes').first();
const binarySource = computeNode.binary || item.binary || {};
const binary_key   = item.json.binary_key;

// Pastikan binary ada
if (!binarySource || Object.keys(binarySource).length === 0) {
  return [{
    json: {
      ...item.json,
      binary_missing: true,
      error: 'Binary foto nota tidak tersedia',
      stage: 'pass_to_layer2'
    }
    // SENGAJA tidak ada binary → akan ditangani error handling
  }];
}

// ✅ Output dengan binary lengkap
// Node ini menjadi "anchor" — binary bisa diambil kembali kapanpun
return [{
  json: {
    upload_id:        item.json.upload_id,
    transaksi_id:     item.json.transaksi_id,
    expected_nominal: item.json.expected_nominal,
    binary_key:       binary_key,
    file_size:        item.json.file_size,
    hashes:           item.json.hashes,
    redis_keys:       item.json.redis_keys,
    binary_missing:   false,
  },
  binary: binarySource  // ← ANCHOR: binary tersimpan di sini permanen
}];

const item = $input.first();

// ✅ PRESERVE data wajib
const upload_id = item.json.upload_id || 'unknown';
const transaksi_id = item.json.transaksi_id || null;

// Ambil binary dari Compute node sebagai fallback
const computeNode = $('[L1] Compute 3 Image Hashes').first();
const binary = item.binary || computeNode.binary || {};

return [{
  json: {
    upload_id,        // ✅ WAJIB preserve
    transaksi_id,     // ✅ WAJIB preserve
    error: 'Resize image gagal',
    stage: 'resize_error',
    resize_failed: true
  },
  binary  // ✅ WAJIB preserve binary
}];

const item = $input.first();

// ✅ PRESERVE data wajib dari item (bukan node reference!)
const anchorNode = $('Resize & Optimize Image1').first();
const upload_id = anchorNode.json.upload_id || 'unknown';
const transaksi_id = anchorNode.json.transaksi_id || null;
const binary = item.binary || {};

const statusCode = item.json.statusCode || item.json.httpCode || 0;
const errorMsg = item.json.error || item.json.message || '';

const is429 = statusCode === 429 || String(errorMsg).includes('429') || String(errorMsg).toLowerCase().includes('rate limit') || String(errorMsg).toLowerCase().includes('quota');
const isError = statusCode >= 400 || !!item.json.error;
const raw_text = item.json.text || item.json.content || item.json.response || JSON.stringify(item.json);

return [{ 
  json: { 
    upload_id,        // ✅ WAJIB preserve
    transaksi_id,     // ✅ WAJIB preserve
    is429, 
    isError, 
    statusCode, 
    errorMsg, 
    raw_text 
  },
  binary  // ✅ WAJIB preserve binary
}];

// ============================================================================
// [FIXED] Parse JSON Response + Hitung Selisih Hari
// ✅ PRESERVE upload_id, transaksi_id, binary di semua return paths
// ✅ ROBUST extraction dari berbagai struktur response Gemini
// ============================================================================

const item = $input.first();

// 🔧 STEP 1: Extract IDs - LANGSUNG dari item, BUKAN node reference!
const upload_id = item.json.upload_id || 'unknown';
const transaksi_id = item.json.transaksi_id || null;

// 🔧 STEP 2: Ambil binary
const binary = item.binary || {};
const binary_key = item.json.binary_key || null;

// 🔧 STEP 3: ROBUST extraction dari berbagai struktur response
function extractText(data) {
  // Null/undefined check
  if (!data) return '';

  // Already a string
  if (typeof data === 'string') return data;

  // Object extraction - try multiple paths
  if (typeof data === 'object') {
    // Path 1: Gemini standard response { parts: [{ text: "..." }], role: "model" }
    if (data.parts && Array.isArray(data.parts) && data.parts.length > 0) {
      if (data.parts[0].text) return data.parts[0].text;
    }

    // Path 2: Direct content.parts structure
    if (data.content?.parts && Array.isArray(data.content.parts) && data.content.parts.length > 0) {
      if (data.content.parts[0].text) return data.content.parts[0].text;
    }

    // Path 3: Direct text property
    if (data.text) return data.text;

    // Path 4: Response property
    if (data.response) return extractText(data.response); // Recursive

    // Path 5: Candidates array (Gemini alternative format)
    if (data.candidates && Array.isArray(data.candidates) && data.candidates.length > 0) {
      const candidate = data.candidates[0];
      if (candidate.content?.parts?.[0]?.text) return candidate.content.parts[0].text;
    }

    // Fallback: stringify
    return JSON.stringify(data);
  }

  return String(data);
}

// Try multiple extraction paths in priority order
let raw = extractText(item.json.raw_text) ||
          extractText(item.json.text) ||
          extractText(item.json.content) ||
          extractText(item.json.response) ||
          extractText(item.json.result) ||
          '';

// 🔧 STEP 4: Validasi response tidak kosong
if (!raw || !raw.trim()) {
  return [{ 
    json: { 
      upload_id,        // ✅ WAJIB preserve
      transaksi_id,     // ✅ WAJIB preserve
      error: 'Response Gemini kosong', 
      stage: 'layer_parse', 
      valid_parse: false,
      valid_date: false,
      auto_reject_reason: 'Response AI OCR kosong',
      debug: {
        raw_text_type: typeof item.json.raw_text,
        raw_text_preview: JSON.stringify(item.json.raw_text).substring(0, 200)
      }
    },
    binary  // ✅ WAJIB preserve binary
  }];
}

// 🔧 STEP 5: Clean & Extract JSON
let cleaned = raw.trim();

// DEBUG: Track original
const debug_raw_preview = raw.substring(0, 300);

// Remove markdown code blocks - try multiple patterns
let codeBlockRemoved = false;

// Pattern 1: Triple backtick with optional json
const tripleBlockMatch = cleaned.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
if (tripleBlockMatch) {
  cleaned = tripleBlockMatch[1];
  codeBlockRemoved = true;
}

// Pattern 2: Single backtick with optional json (more greedy to handle newlines)
if (!codeBlockRemoved) {
  const singleBlockMatch = cleaned.match(/`(?:json)?[\s\n]*([\s\S]*?)[\s\n]*`/);
  if (singleBlockMatch) {
    cleaned = singleBlockMatch[1];
    codeBlockRemoved = true;
  }
}

cleaned = cleaned.trim();

// DEBUG: Track after backtick removal
const debug_cleaned_preview = cleaned.substring(0, 300);

// Extract JSON object - use greedy match to get full object
const jsonMatch = cleaned.match(/(\{[\s\S]*\})/);
if (!jsonMatch) {
  return [{ 
    json: { 
      upload_id,        // ✅ WAJIB preserve
      transaksi_id,     // ✅ WAJIB preserve
      error: 'Tidak ada JSON object dalam response', 
      stage: 'layer_parse', 
      valid_parse: false,
      valid_date: false,
      auto_reject_reason: 'Format response tidak mengandung JSON',
      debug: {
        raw_preview: debug_raw_preview,
        cleaned_preview: debug_cleaned_preview,
        code_block_removed: codeBlockRemoved
      }
    },
    binary  // ✅ WAJIB preserve binary
  }];
}

// DEBUG: Track JSON string
const debug_json_preview = jsonMatch[0].substring(0, 300);

let parsed;
try { 
  parsed = JSON.parse(jsonMatch[0]); 
} catch(err) {
  return [{ 
    json: { 
      upload_id,        // ✅ WAJIB preserve
      transaksi_id,     // ✅ WAJIB preserve
      error: 'Format JSON tidak valid: ' + err.message,
      stage: 'layer_parse', 
      valid_parse: false,
      valid_date: false,
      auto_reject_reason: 'JSON parse error: ' + err.message,
      debug: {
        raw_preview: debug_raw_preview,
        cleaned_preview: debug_cleaned_preview,
        json_preview: debug_json_preview,
        error_message: err.message
      }
    },
    binary  // ✅ WAJIB preserve binary
  }];
}

// DEBUG: Track parsed object keys
const debug_parsed_keys = Object.keys(parsed);
const debug_parsed_preview = JSON.stringify(parsed).substring(0, 300);

// 🔧 STEP 6: Helper functions
function fmtDateISO(ds) {
  if (!ds) return null;
  const d = new Date(ds);
  if (isNaN(d.getTime())) return null;
  return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;
}

function parseDate(ds) {
  if (!ds) return null;

  // handle DD/MM/YYYY
  const parts = ds.split('/');
  if (parts.length === 3) {
    return new Date(`${parts[2]}-${parts[1]}-${parts[0]}`);
  }

  const d = new Date(ds);
  return isNaN(d.getTime()) ? null : d;
}

// 🔧 STEP 7: Extract tanggal & hitung selisih hari
let tanggal_nota = null;
let selisih_hari = 0;
let valid_date = true;
let auto_reject_reason = null;

const tanggalRaw = parsed.tanggal_nota || parsed.tanggal || parsed.transaction_date || null;

if (tanggalRaw) {
  const nota_date = parseDate(tanggalRaw);
  if (nota_date) {
    tanggal_nota = fmtDateISO(tanggalRaw);

    const today = new Date();
    today.setHours(0, 0, 0, 0);
    nota_date.setHours(0, 0, 0, 0);

    selisih_hari = Math.abs(Math.round((today.getTime() - nota_date.getTime()) / 86400000));
    valid_date = selisih_hari <= 2;

    if (!valid_date) {
      auto_reject_reason = `Nota tanggal ${tanggal_nota} - selisih ${selisih_hari} hari dari hari ini (maks 2 hari)`;
    }
  }
}

// 🔧 STEP 8: Extract data receipt
const rawItems = parsed.items || [];
const overallConf = Number(parsed.overall_confidence) || Number(parsed.confidence) || 0;
const confLabel = overallConf > 70 ? 'HIGH' : 'LOW';

const fieldConfidence = {
  vendor: Number(parsed.nama_vendor_confidence) || overallConf,
  tanggal: Number(parsed.tanggal_confidence) || overallConf,
  total_belanja: Number(parsed.total_belanja_confidence) || overallConf,
  material: rawItems[0] ? Number(rawItems[0].nama_barang_confidence) || overallConf : overallConf,
  jumlah: rawItems[0] ? Number(rawItems[0].qty_confidence) || overallConf : overallConf,
  satuan: rawItems[0] ? Number(rawItems[0].satuan_confidence) || overallConf : overallConf,
  nominal: rawItems[0] ? Number(rawItems[0].total_harga_confidence) || overallConf : overallConf,
};

// 🔧 STEP 9: Build final output
return [{
  json: {
    // 📌 IDs - WAJIB preserve
    upload_id,
    transaksi_id,
    binary_key,

    // 📌 Parsing result
    valid_parse: true,
    valid_date,
    selisih_hari,
    auto_reject_reason,

    // 📌 Extracted data
    nama_vendor: parsed.nama_vendor || parsed.vendor || null,
    tanggal: tanggal_nota,
    total_belanja: Number(parsed.total_belanja) || Number(parsed.total) || 0,

    // 📌 Confidence metrics
    overall_confidence: overallConf,
    confidence_label: confLabel,
    field_confidence: fieldConfidence,

    // 📌 Items array
    items: Array.isArray(rawItems) ? rawItems.map(i => ({
      nama_barang: i.nama_barang || i.nama_item || i.product || null,
      qty: Number(i.qty) || Number(i.quantity) || 0,
      satuan: i.satuan || i.unit || "Unit",
      harga_satuan: Number(i.harga_satuan) || Number(i.price) || 0,
      total_harga: Number(i.total_harga) || Number(i.total) || 0,
      nama_barang_confidence: Number(i.nama_barang_confidence) || overallConf,
      qty_confidence: Number(i.qty_confidence) || overallConf,
      satuan_confidence: Number(i.satuan_confidence) || 70,
      harga_satuan_confidence: Number(i.harga_satuan_confidence) || overallConf,
      total_harga_confidence: Number(i.total_harga_confidence) || overallConf,
    })) : [],

    // 📌 DEBUG - remove after testing
    _debug: {
      raw_preview: debug_raw_preview,
      cleaned_preview: debug_cleaned_preview,
      json_preview: debug_json_preview,
      parsed_keys: debug_parsed_keys,
      parsed_preview: debug_parsed_preview
    }
  },
  binary  // ✅ WAJIB preserve binary
}];

// Restore Binary sebelum Resize & Optimize Image
const item = $input.first();

// ✅ PRESERVE data wajib
const upload_id = item.json.upload_id || 'unknown';
const transaksi_id = item.json.transaksi_id || null;

// ✅ Selalu ambil binary dari Anchor node [L1] Pass to Layer 2
const anchor     = $('[L1] Pass to Layer 1').first();
const binaryData = anchor.binary || {};
const binary_key = item.json.binary_key || anchor.json.binary_key;

if (!binaryData || Object.keys(binaryData).length === 0) {
  return [{
    json: {
      upload_id,      // ✅ WAJIB preserve
      transaksi_id,   // ✅ WAJIB preserve
      binary_key,
      error: 'Binary foto nota tidak tersedia untuk Resize',
      stage: 'restore_binary_pre_resize'
    }
    // Tanpa binary → Has Resize Error akan menangkap ini
  }];
}

// ✅ Binary berhasil dipulihkan — siap untuk Resize
return [{
  json: { 
    ...item.json,
    upload_id,        // ✅ WAJIB preserve (explicit)
    transaksi_id,     // ✅ WAJIB preserve (explicit)
    binary_key 
  },
  binary: binaryData  // ✅ WAJIB preserve binary
}];

const item = $input.first();
const body = item.json.body || item.json;
const binary = item.binary || {};
const transaksi_id = body.transaksi_id || null;
const upload_id = body.upload_id || null;
const binaryKeys = Object.keys(binary);
const hasFoto = binaryKeys.length > 0;

if (!transaksi_id || !upload_id) {
  return [{ json: { error: 'transaksi_id / upload_id tidak ditemukan', valid: false, upload_id } }];
}
if (!hasFoto) {
  return [{ json: { error: 'Foto penyerahan tidak ditemukan', valid: false, upload_id } }];
}

return [{ json: { upload_id, transaksi_id, valid: true, foto_key: binaryKeys[0] }, binary: item.binary }];

const item = $input.first();
const body = item.json.body || item.json || {};
const binary = item.binary || {};

// ✅ PRESERVE data wajib
const upload_id = body.upload_id || item.json.upload_id || 'unknown';
const transaksi_id = body.transaksi_id || item.json.transaksi_id || null;
const konfirmasi = body.konfirmasi || null;

if (!upload_id || !konfirmasi) {
  return [{
    json: {
      upload_id,
      transaksi_id,
      error: 'upload_id atau konfirmasi tidak ditemukan',
      valid: false
    },
    binary
  }];
}

return [{
  json: {
    upload_id,        // ✅ WAJIB preserve
    transaksi_id,     // ✅ WAJIB preserve
    konfirmasi,
    valid: true
  },
  binary  // ✅ WAJIB preserve binary
}];

const item = $input.first();
const body = item.json.body || item.json;
const binary = item.binary || {};
const transaksi_id = body.transaksi_id || null;
const upload_id = body.upload_id || null;
const expected_nominal = Number(body.expected_nominal) || 0;
const kode_unik = Number(body.kode_unik) || 0;
const biaya_admin = Number(body.biaya_admin) || 0;
const rekening_tujuan = body.rekening_tujuan || null;
const rekening_nomor = Number(body.rekening_nomor) || null;
const rekening_nama = body.rekening_nama || null;
const binaryKeys = Object.keys(binary);
const hasBukti = binaryKeys.length > 0;

if (!transaksi_id || !upload_id || !expected_nominal) {
  return [{ json: { error: 'Data tidak lengkap (transaksi_id/upload_id/expected_nominal wajib)', valid: false, upload_id } }];
}
if (!hasBukti) {
  return [{ json: { error: 'Bukti transfer tidak ditemukan', valid: false, upload_id } }];
}

const expected_total = expected_nominal + biaya_admin + kode_unik;

return [{ 
  json: { upload_id, transaksi_id, expected_nominal, biaya_admin, kode_unik, expected_total, rekening_tujuan,rekening_nomor, rekening_nama, valid: true, bukti_key: binaryKeys[0] }, 
  binary: item.binary 
}];

// ========================================
// NODE: [OCR] Check 429 Transfer (FIXED)
// ========================================

const item = $input.first();

// ✅ Preserve dari item saat ini (bukan node reference!)
const upload_id = item.json.upload_id || 'unknown';
const transaksi_id = item.json.transaksi_id || null;
const binary = item.binary || {};

// ✅ Check error status
const statusCode = item.json.statusCode || item.json.httpCode || item.json.errorCode || 0;
const errorMsg = item.json.error || item.json.message || item.json.errorMessage || '';

// ✅ Detect 429
const is429 = statusCode === 429 || String(errorMsg).includes('429') || String(errorMsg).includes('rate limit');
const isError = statusCode >= 400 || !!item.json.error || !!item.json.errorMessage;

// ✅ Preserve retry counter
const retry_count = item.json.retry_count || 0;
const max_retries = 3;

return [{
  json: {
    upload_id,
    transaksi_id,
    is429,
    isError,
    statusCode,
    errorMsg,
    retry_count,
    max_retries,
    can_retry: is429 && retry_count < max_retries,
    // ✅ Spread all OCR data
    ...item.json
  },
  binary // ✅ Preserve binary
}];

// ========================================
// NODE: [OCR] Parse & Verifikasi Nominal (FIXED)
// ========================================

const item = $input.first();

// ✅ Preserve dari item saat ini
const upload_id = item.json.upload_id || 'unknown';
const transaksi_id = item.json.transaksi_id || null;
const binary = item.binary || {};

// ✅ Expected values
const expected_nominal = Number(item.json.expected_nominal) || 0;
const expected_biaya_admin = Number(item.json.expected_biaya_admin) || 0;
const expected_kode_unik = Number(item.json.expected_kode_unik) || 0;
const expected_total = Number(item.json.expected_total) || 0;

// ✅ OCR Extracted values (STANDARDIZED: actual_*)
const actual_nominal = Number(item.json.actual_nominal) || 0;
const actual_biaya_admin = Number(item.json.actual_biaya_admin) || 0;
const actual_kode_unik = Number(item.json.actual_kode_unik) || 0;
const actual_total = Number(item.json.actual_total) || 0;

// ✅ Verification with tolerance (gunakan TOTAL, bukan nominal saja)
const selisih = Math.abs(actual_total - expected_total);
const tolerance = 1000;
const is_match = selisih <= tolerance;
const status = is_match ? 'match' : 'mismatch';
const flag_reason = is_match ? null : `Selisih ${selisih} melebihi tolerance ${tolerance}`;

return [{
  json: {
    // ✅ WAJIB preserve
    upload_id,
    transaksi_id,

    // ✅ Expected
    expected_nominal,
    expected_biaya_admin,
    expected_kode_unik,
    expected_total,

    // ✅ Actual (standardized naming)
    actual_nominal,
    actual_biaya_admin,
    actual_kode_unik,
    actual_total,

    // ✅ Verification
    selisih,
    tolerance,
    is_match,
    status,
    flag_reason,

    // ✅ OCR Metadata for callback (LENGKAP)
    rekening_pengirim: item.json.rekening_pengirim || null,
    rekening_tujuan: item.json.rekening_tujuan || null,
    nama_tujuan: item.json.nama_tujuan || null,
    tanggal_transfer: item.json.tanggal_transfer || null,
    bank_tujuan: item.json.bank_tujuan || null,
    status_transfer: item.json.status_transfer || 'UNKNOWN',
    ocr_confidence: item.json.ocr_confidence || 0,

    // ✅ Error/Retry info
    is429: item.json.is429 || false,
    isError: item.json.isError || false,
    statusCode: item.json.statusCode || 0,
    errorMsg: item.json.errorMsg || '',
    retry_count: item.json.retry_count || 0,
    max_retries: item.json.max_retries || 3,

    // ✅ Timestamp
    processed_at: new Date().toISOString()
  },
  binary // ✅ Preserve binary
}];

// ═══════════════════════════════════════════════════════════════
//  VALIDATE & EXTRACT — FINAL FIX v2
//  
//  ✅ Membaca upload_id dari 4 sumber (prioritas):
//     1. URL query params (paling reliable)
//     2. HTTP Headers (X-Upload-ID)
//     3. Filename (extract dari nama file)
//     4. Body fields (fallback terakhir)
//
//  ✅ Membaca transaksi_id dengan cara yang sama
//  ✅ Validasi bahwa upload_id valid (bukan "unknown" atau "null")
// ═══════════════════════════════════════════════════════════════

const item = $input.first();

// ── Extract dari berbagai sumber ──
const query = item.json.query || {};
const headers = item.json.headers || {};
const body = item.json.body || item.json || {};
const binary = item.binary || {};

// ── Helper: Validasi upload_id ──
function isValidId(id) {
  return id 
    && typeof id === 'string' 
    && id !== 'unknown' 
    && id !== 'null'
    && id !== 'undefined'
    && !id.includes('{{')
    && !id.includes('}}')
    && id.length >= 10; // Upload ID minimal 10 karakter
}

// ── PRIORITAS 1: Query params (paling reliable untuk n8n webhook) ──
let upload_id = query.upload_id || null;
let transaksi_id = query.transaksi_id || null;

// ── PRIORITAS 2: HTTP Headers ──
if (!isValidId(upload_id)) {
  upload_id = headers['x-upload-id'] || headers['X-Upload-ID'] || null;
}
if (!transaksi_id) {
  transaksi_id = headers['x-transaksi-id'] || headers['X-Transaksi-ID'] || null;
}

// ── PRIORITAS 3: Extract dari filename binary ──
if (!isValidId(upload_id)) {
  const binaryKeys = Object.keys(binary);
  if (binaryKeys.length > 0) {
    const filename = binary[binaryKeys[0]]?.fileName || '';
    // Filename format: "upload_id.ext" (e.g., "67890abcdef.jpg")
    const match = filename.match(/^([a-zA-Z0-9]{10,})\./);
    if (match) {
      upload_id = match[1];
    }
  }
}

// ── PRIORITAS 4: Body fields (fallback terakhir) ──
if (!isValidId(upload_id)) {
  upload_id = body.upload_id || null;
}
if (!transaksi_id) {
  transaksi_id = body.transaksi_id || null;
}

// ── Extract other fields ──
const expected_nominal = Number(body.expected_nominal || 0);
const binaryKeys = Object.keys(binary);
const hasImage = binaryKeys.length > 0;

// ── Debug info ──
const debug = {
  sources: {
    query_upload_id: query.upload_id || 'NOT_FOUND',
    header_upload_id: headers['x-upload-id'] || 'NOT_FOUND',
    body_upload_id: body.upload_id || 'NOT_FOUND',
    filename: binary[binaryKeys[0]]?.fileName || 'NO_BINARY',
  },
  resolved: {
    upload_id,
    transaksi_id,
  },
  binaryKeys,
  jsonKeys: Object.keys(body),
};

// ── Validasi final ──
if (!isValidId(upload_id)) {
  return [{
    json: {
      error: 'upload_id tidak valid atau tidak ditemukan',
      stage: 'validation',
      upload_id: upload_id || 'INVALID',
      debug,
      valid: false
    }
  }];
}

if (!hasImage) {
  return [{
    json: {
      error: 'Binary image tidak ditemukan',
      stage: 'validation',
      upload_id,
      debug,
      valid: false
    }
